use std::mem;

struct FixedPoint {
    value: i64
}

impl Clone for FixedPoint {
    fn clone(&self) -> Self {
        FixedPoint { value: self.value }
    }
}

impl FixedPoint {
    fn new(integer_part: i64) -> Self {
        FixedPoint { value: integer_part }
    }

    fn multiply(self, other: FixedPoint) -> Self {
        let result_i64 = (self.value * other.value) / 10000;
        FixedPoint { value: result_i64 }
    }

    fn display(&self) -> String {
        format!("{:.4}", self.value as f64 / 10000.0)
    }
}

fn main() {
    let price1 = FixedPoint::new(12345); 
    let quantity2 = FixedPoint::new(6789); 

    let total = price1.clone().multiply(quantity2.clone());

    println!("Price: {}", price1.display());
    println!("Quantity: {}", quantity2.display());
    println!("Total Result: {}", total.display());
}

