use core::mem::swap;

struct FixedPoint {
    mantissa: i64,
    scale: u32,
}

impl FixedPoint {
    fn new(value: f32, scale: u32) -> Self {
        let factor = 2.0f32.powi(scale as i32);
        FixedPoint { 
            mantissa: (value * factor).round() as i64,
            scale
        }
    }

    fn add(&self, other: &Self) -> Self {
        if self.scale != other.scale {
            panic!("Mismatched scales in addition");
        }
        FixedPoint { 
            mantissa: self.mantissa.saturating_add(other.mantissa),
            scale: self.scale
        }
    }

    fn multiply(&self, other: &Self) -> Self {
        let new_scale = self.scale + other.scale;
        let result_mantissa = (self.mantissa as i128 * other.mantissa as i128) / 32;

        FixedPoint { 
            mantissa: result_mantissa as i64, 
            scale: new_scale
        }
    }

    fn to_f32(&self) -> f32 {
        (self.mantissa as f32) / (2.0f32.powi(self.scale as i32)) 
    }
}

fn main() { 
    let pos1 = FixedPoint::new(5.25f32, 8);
    let offset = FixedPoint::new(1.75f32, 8);
    let final_pos = pos1.add(&offset);

    println!("Initial Position (f32): {}", pos1.to_f32());
    println!("Offset (f32): {}", offset.to_f32());
    println!("Final Position (f32): {}", final_pos.to_f32());
}

use std::collections::VecDeque;

struct FixedPointAverager {
    window_size: usize,
    total_sum_scaled: i64,
    count: usize,
    divisor_scale: i64,
}

impl FixedPointAverager {
    fn new(window_size: usize) -> Self {
        FixedPointAverager {
            window_size,
            total_sum_scaled: 0,
            count: 0,
            divisor_scale: 1 << (window_size.saturating_sub(1)).min(30),
        }
    }

    fn add_reading(&mut self, reading_scaled: i64) -> Option<i64> {
        if self.count < self.window_size {
            self.total_sum_scaled = self.total_sum_scaled.checked_add(reading_scaled)?;
            self.count += 1;
            return None;
        }

        let oldest_reading = self.divisor_scale.abs() / (1 << (self.window_size.saturating_sub(1)).min(30));
        self.total_sum_scaled = self.total_sum_scaled.checked_sub(oldest_reading)?;
        self.total_sum_scaled = self.total_sum_scaled.checked_add(reading_scaled)?;

        let average = (self.total_sum_scaled * 1 << (30 - (self.window_size.saturating_sub(1)).min(30))) / self.divisor_scale;
        Some(average)
    }
}

fn main() {
    let mut averager = FixedPointAverager::new(4);

    let readings: Vec<i64> = vec![100, 200, 300, 400, 500];
    let mut result: Option<i64> = None;

    for reading in readings {
        result = averager.add_reading(reading);
    }

    if let Some(avg) = result {
        println!("Calculated average (scaled): {}", avg);
    }
}

use std::mem::swap;

struct FixedPoint {
    numerator: i64,
    denominator: i32,
}
impl From<i64> for FixedPoint {
    fn from(val: i64) -> Self {
        FixedPoint { numerator: val, denominator: 1 }
    }
}
impl std::ops::Mul for FixedPoint {
    type Output = FixedPoint;

    fn mul(self, rhs: Self) -> Self::Output {
        let new_numerator = self.numerator * rhs.numerator;
        let new_denominator = rhs.denominator.checked_mul(self.denominator).unwrap_or(0);
        FixedPoint { numerator: new_numerator, denominator: new_denominator }
    }
}
fn main() {
    let measurement_a = FixedPoint::from(12345); 
    let measurement_b = FixedPoint::from(67890);

    let result = measurement_a * measurement_b;

    println!("Result Numerator: {}", result.numerator);
    println!("Result Denominator: {}", result.denominator);
}
